#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class LRUCache {
private:
    int capacity;
    list<pair<int, int>> lru;
    unordered_map<int, list<pair<int, int>>::iterator> cache;

public:
    LRUCache(int capacity) {
        this->capacity = capacity;
    }

    int get(int key) {
        if (cache.find(key) != cache.end()) {
            auto it = cache[key];
            lru.splice(lru.end(), lru, it);
            return it->second;
        }
        return -1;
    }

    void put(int key, int value) {
        if (cache.find(key) != cache.end()) {
            lru.erase(cache[key]);
        } else if (lru.size() >= capacity) {
            cache.erase(lru.front().first);
            lru.pop_front();
        }
        lru.push_back({key, value});
        cache[key] = --lru.end();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int capacity, Q;
    if (!(cin >> capacity >> Q)) return 0;
    LRUCache sol(capacity);
    for (int i = 0; i < Q; i++) {
        string query;
        cin >> query;
        if (query == "put") {
            int key, value;
            if (!(cin >> key >> value)) return 0;
            sol.put(key, value);
        } else if (query == "get") {
            int key;
            if (!(cin >> key)) return 0;
            cout << sol.get(key) << "\n";
        }
    }
    return 0;
}
